#include<bits/stdc++.h>
using namespace std;

int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        int sum=0;
        priority_queue<int> q;
        for(int i=1;i<=n;i++)
        {
            char ch;
            cin>>ch;
            int x=ch-'0';
            sum+=x*10;
            q.push(x);
            if((int)q.size()>i/2)
            {
                q.pop();
            }
        }
        while(!q.empty())
        {
            sum-=q.top()*9;
            q.pop();
        }
        printf("%lld\n",sum);
    }
    return 0;
}
